import React from 'react';

export interface ComponentContextType {
    componentId: string;
    name?: string;
}

export const ComponentContext = React.createContext<ComponentContextType | null>(null);

export const useComponentContext = (): ComponentContextType | null => React.useContext(ComponentContext);
